using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration -----------------------------------------------------------

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running this app.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Tools -------------------------------------------------------------------

var notebook = new ResearchNotebook();

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

var tools = new AITool[]
{
    AIFunctionFactory.Create(
        (string query) => WebSearchTool.SearchAsync(query),
        "web_search",
        "Searches the web for the given query and returns a list of result snippets with titles and URLs."),

    AIFunctionFactory.Create(
        ([Description("A concise heading for this note")] string title,
         [Description("The note content — a fact, quote, or insight worth remembering")] string content,
         [Description("The source URL, if available")] string? sourceUrl) =>
        {
            notebook.AddNote(title, content, sourceUrl);
            return $"Note saved: \"{title}\"";
        },
        "save_note",
        "Saves a research note to the notebook for later reference in the summary."),

    AIFunctionFactory.Create(
        () => notebook.GetAllNotes(),
        "get_notes",
        "Returns all notes saved so far in this research session."),
};

// --- Agent -------------------------------------------------------------------

var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research assistant. When the user gives you a topic:

        1. Search the web 2-3 times with varied queries to gather diverse information.
        2. For each useful finding, save a note with a clear title, the key insight, and the source URL.
        3. After gathering enough notes, review them with get_notes.
        4. Produce a well-structured summary with:
           - An overview paragraph
           - Key findings as bullet points
           - A "Sources" section listing URLs

